<?php include __DIR__.'/_init.php'; if($_SERVER['REQUEST_METHOD']==='POST'){if(!verify_csrf($_POST['csrf_token']??''))die('CSRF');foreach($_POST['settings'] as $k=>$v){$db->prepare('INSERT INTO site_settings(setting_key,setting_value) VALUES(?,?) ON DUPLICATE KEY UPDATE setting_value=VALUES(setting_value)')->execute([$k,sanitize($v)]);}redirect('/admin/content.php');}
$settings=$db->query('SELECT setting_key,setting_value FROM site_settings')->fetchAll(PDO::FETCH_KEY_PAIR);?><h2>Website Content Settings</h2><form method="post"><input type="hidden" name="csrf_token" value="<?=csrf_token()?>"><input name="settings[site_title]" value="<?=e($settings['site_title']??'')?>" placeholder="Site Title"><input name="settings[site_description]" value="<?=e($settings['site_description']??'')?>" placeholder="Site Description"><input name="settings[hero_title]" value="<?=e($settings['hero_title']??'')?>" placeholder="Hero Title"><textarea name="settings[hero_subtitle]"><?=e($settings['hero_subtitle']??'')?></textarea><button>Save</button></form>
